const coupons = new Map();

// Initialize with some sample data
coupons.set('SAVE10', { value: 10, validUntil: '2023-12-31T23:59:59Z' });
coupons.set('FREESHIP', { value: null, validUntil: '2024-01-31T23:59:59Z' });

async function applyCoupon(userId, couponCode) {
    if (!userId || !couponCode) return { success: false, message: 'Missing required fields' };

    const coupon = coupons.get(couponCode);
    if (!coupon) return { success: false, message: 'Invalid coupon code' };

    if (new Date() > new Date(coupon.validUntil)) {
        return { success: false, message: 'Coupon has expired' };
    }

    if (await isCouponUsedByUser(userId, couponCode)) {
        return { success: false, message: 'Coupon has already been used' };
    }

    await markCouponAsUsed(userId, couponCode);
    const discount = coupon.value ? coupon.value : 1; // Assuming 1 for FREEESHIP

    return { success: true, message: `Discount of ${discount}% applied`, discount };
}

async function isCouponUsedByUser(userId, couponCode) {
    // Simulate database check
    return new Promise(resolve => setTimeout(() => resolve(false), 50));
}

async function markCouponAsUsed(userId, couponCode) {
    // Simulate marking the coupon as used in a database
    return new Promise(resolve => setTimeout(() => resolve(), 100));
}